import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        char[] buffer = new char[input.length()]; // Dynamically allocate buffer based on input length

        // Copy user input into the buffer with bounds checking
        for (int i = 0; i < input.length(); i++) {
            if (i < buffer.length) {
                buffer[i] = input.charAt(i);
            } else {
                break; // Exit loop if buffer size exceeded
            }
        }

        System.out.println("Buffer overflow fixed!");
    }
}

